    // ========== NEW METHOD: Get Login Credentials by Environment ==========
    /**
     * Retrieve login credentials from LoginData.xlsx based on environment
     * @param excelPath Path to LoginData.xlsx file
     * @param sheetName Sheet name (e.g., "LoginData")
     * @param environment Environment name to match (e.g., "dev", "staging", "prod")
     * @return Hashtable containing EMAIL and PASSWORD, or null if not found
     */
    public Hashtable<String, String> getLoginCredentialsByEnvironment(String excelPath, String sheetName, String environment) {
        Hashtable<String, String> credentials = new Hashtable<>();

        try {
            File excelFile = new File(excelPath);
            if (!excelFile.exists()) {
                System.err.println("❌ Excel file not found: " + excelPath);
                return null;
            }

            try (FileInputStream inputStream = new FileInputStream(excelFile)) {
                Workbook workbook = WorkbookFactory.create(inputStream);
                Sheet sheet = workbook.getSheet(sheetName);

                if (sheet == null) {
                    System.err.println("❌ Sheet not found: " + sheetName);
                    return null;
                }

                // Find the ENVIRONMENT, EMAIL, and PASSWORD column indices
                Row headerRow = sheet.getRow(0);
                if (headerRow == null) {
                    System.err.println("❌ Header row not found in sheet: " + sheetName);
                    return null;
                }

                int envColumnIndex = -1;
                int emailColumnIndex = -1;
                int passwordColumnIndex = -1;

                // Get column indices by header names
                for (int i = 0; i < headerRow.getLastCellNum(); i++) {
                    Cell cell = headerRow.getCell(i);
                    if (cell != null) {
                        String headerValue = getCellStringValue(cell);
                        if ("ENVIRONMENT".equalsIgnoreCase(headerValue)) {
                            envColumnIndex = i;
                        } else if ("EMAIL".equalsIgnoreCase(headerValue)) {
                            emailColumnIndex = i;
                        } else if ("PASSWORD".equalsIgnoreCase(headerValue)) {
                            passwordColumnIndex = i;
                        }
                    }
                }

                // Verify all required columns exist
                if (envColumnIndex == -1 || emailColumnIndex == -1 || passwordColumnIndex == -1) {
                    System.err.println("❌ Required columns (ENVIRONMENT, EMAIL, PASSWORD) not found in sheet: " + sheetName);
                    return null;
                }

                // Search for the row matching the environment
                for (int rowIndex = 1; rowIndex <= sheet.getLastRowNum(); rowIndex++) {
                    Row dataRow = sheet.getRow(rowIndex);
                    if (dataRow == null) continue;

                    Cell envCell = dataRow.getCell(envColumnIndex);
                    String currentEnv = getCellStringValue(envCell);

                    if (environment.equalsIgnoreCase(currentEnv.trim())) {
                        String email = getCellStringValue(dataRow.getCell(emailColumnIndex));
                        String password = getCellStringValue(dataRow.getCell(passwordColumnIndex));

                        credentials.put("ENVIRONMENT", environment);
                        credentials.put("EMAIL", email);
                        credentials.put("PASSWORD", password);

                        System.out.println("✅ Login credentials found for environment: " + environment);
                        System.out.println("   Email: " + email);
                        System.out.println("   Password: " + (password.isEmpty() ? "[empty]" : "[masked]"));

                        workbook.close();
                        return credentials;
                    }
                }

                System.err.println("❌ No credentials found for environment: " + environment);
                workbook.close();
            }
        } catch (IOException e) {
            System.err.println("❌ Error reading Excel file: " + e.getMessage());
            e.printStackTrace();
        }

        return null;
    }

    // ========== HELPER METHOD: Get Login Credentials with Default File Path ==========
    /**
     * Convenience method to get login credentials from default data/LoginData.xlsx
     * @param environment Environment name (e.g., "dev", "staging", "prod")
     * @return Hashtable containing EMAIL and PASSWORD
     */
    public Hashtable<String, String> getLoginCredentialsByEnvironment(String environment) {
        return getLoginCredentialsByEnvironment("data/LoginData.xlsx", "LoginData", environment);
    }
}

package helpers;

import java.util.Hashtable;
import utils.LogUtils;

/**
 * Helper class to store and manage login credentials loaded from Excel
 * This replaces the need to use ConstantGlobal for login credentials
 */
public class LoginDataHelper {
    private static LoginDataHelper instance;
    private String environment;
    private String email;
    private String password;

    private LoginDataHelper() {
        // Private constructor for singleton pattern
    }

    /**
     * Get singleton instance
     */
    public static synchronized LoginDataHelper getInstance() {
        if (instance == null) {
            instance = new LoginDataHelper();
        }
        return instance;
    }

    /**
     * Initialize login data from Excel based on environment
     * @param environment The environment name (e.g., "dev", "staging", "prod")
     */
    public static void initializeFromExcel(String environment) {
        ExcelHelper excelHelper = new ExcelHelper();
        Hashtable<String, String> credentials = excelHelper.getLoginCredentialsByEnvironment(environment);

        if (credentials != null && !credentials.isEmpty()) {
            getInstance().environment = credentials.get("ENVIRONMENT");
            getInstance().email = credentials.get("EMAIL");
            getInstance().password = credentials.get("PASSWORD");

            LogUtils.info("✅ LoginDataHelper initialized for environment: " + environment);
        } else {
            LogUtils.error("❌ Failed to load login credentials for environment: " + environment);
            throw new RuntimeException("Unable to load login credentials from Excel for environment: " + environment);
        }
    }

    /**
     * Get the current environment
     */
    public String getEnvironment() {
        return this.environment;
    }

    /**
     * Get the current email
     */
    public String getEmail() {
        return this.email;
    }

    /**
     * Get the current password
     */
    public String getPassword() {
        return this.password;
    }

    /**
     * Convenience static method to get email
     */
    public static String getCurrentEmail() {
        return getInstance().getEmail();
    }

    /**
     * Convenience static method to get password
     */
    public static String getCurrentPassword() {
        return getInstance().getPassword();
    }

    /**
     * Convenience static method to get environment
     */
    public static String getCurrentEnvironment() {
        return getInstance().getEnvironment();
    }

    /**
     * Reset the helper (useful for test cleanup)
     */
    public static void reset() {
        instance = null;
    }

    @Override
    public String toString() {
        return "LoginDataHelper{" +
                "environment='" + environment + '\'' +
                ", email='" + email + '\'' +
                ", password='[MASKED]'" +
                '}';
    }
}

