package hooks;

import constants.ConstantGlobal;
import factory.DriverFactory;
import factory.DriverManager;
import helpers.PropertiesHelper;
import helpers.UserInfoHelper;
import io.cucumber.java.*;
import reports.AllureManager;
import reports.ExtentTestManager;
import utils.LogUtils;

public class CucumberHooks {
    private static final String SEPARATOR = "=".repeat(40);

    @BeforeAll
    public static void beforeAll() {
        LogUtils.info(SEPARATOR);
        LogUtils.info("STARTING TEST SUITE");
        LogUtils.info(SEPARATOR);
        PropertiesHelper.loadAllFiles();

        // ========== ENHANCEMENT: Log user info at suite level ==========
        LogUtils.info(UserInfoHelper.getUserTestHeader());
    }

    @AfterAll
    public static void afterAll() {
        LogUtils.info(SEPARATOR);
        LogUtils.info("TEST SUITE COMPLETED");
        LogUtils.info(SEPARATOR);
    }

    @Before
    public void beforeScenario(Scenario scenario) {
        LogUtils.info("SCENARIO START: " + scenario.getName());
        LogUtils.info("SCENARIO STATUS: Starting");

        if (DriverManager.getDriver() == null) {
            new DriverFactory().createDriver();
            LogUtils.info("Driver initialized for scenario: " + scenario.getName());
        }

        try {
            String testName = scenario.getName();
            ExtentTestManager.createTest(testName);
            LogUtils.info("ExtentTest initialized for: " + testName);

            // Log scenario info to ExtentReport
            if (ExtentTestManager.getTest() != null) {
                ExtentTestManager.getTest().info("Starting scenario: " + testName);

                // ========== ENHANCEMENT: Log user info to Extent Report ==========
                ExtentTestManager.getTest().info("Test User: " + ConstantGlobal.VALID_EMAIL);
                ExtentTestManager.getTest().info("Environment: " + ConstantGlobal.ENV);
                ExtentTestManager.getTest().info("Account Type: " + UserInfoHelper.getUserAccountType());
            }

            // ========== ENHANCEMENT: Attach user info to Allure Report ==========
            AllureManager.attachEnvironmentInfo();
            AllureManager.attachUserAccountInfo();

        } catch (Exception e) {
            LogUtils.info("Failed to create ExtentTest: " + e.getMessage());
        }
    }

    @After
    public void afterScenario(Scenario scenario) {
        String status = "PASSED";
        try {
            Object statusObj = scenario.getClass().getMethod("getStatus").invoke(scenario);
            if (statusObj != null) {
                status = statusObj.toString();
            } else {
                status = scenario.isFailed() ? "FAILED" : "PASSED";
            }
        } catch (NoSuchMethodException nsme) {
            status = scenario.isFailed() ? "FAILED" : "PASSED";
        } catch (Exception e) {
            status = scenario.isFailed() ? "FAILED" : "PASSED";
        }

        try {
            if (ExtentTestManager.getTest() != null) {
                if ("FAILED".equalsIgnoreCase(status)) {
                    ExtentTestManager.getTest().fail("Scenario Failed: " + scenario.getName());
                    // ========== ENHANCEMENT: Attach summary on failure ==========
                    AllureManager.attachTestResultSummary(scenario.getName(), "FAILED");
                } else if ("SKIPPED".equalsIgnoreCase(status) || "UNKNOWN".equalsIgnoreCase(status)) {
                    ExtentTestManager.getTest().skip("Scenario Skipped: " + scenario.getName());
                } else {
                    ExtentTestManager.getTest().pass("Scenario Passed: " + scenario.getName());
                    // ========== ENHANCEMENT: Attach summary on pass ==========
                    AllureManager.attachTestResultSummary(scenario.getName(), "PASSED");
                }
            }
        } catch (Exception e) {
            LogUtils.error("Failed to log scenario status to ExtentReport: " + e.getMessage());
        }

        LogUtils.info("SCENARIO FINISHED: " + scenario.getName());
        LogUtils.info("SCENARIO STATUS: " + status);

        DriverManager.quit();
        LogUtils.info(SEPARATOR + "\n");

        TestContext.reset();
    }

}

package hooks;

import constants.ConstantGlobal;
import factory.DriverFactory;
import factory.DriverManager;
import helpers.LoginDataHelper;
import helpers.PropertiesHelper;
import helpers.UserInfoHelper;
import io.cucumber.java.*;
import reports.AllureManager;
import reports.ExtentTestManager;
import utils.LogUtils;

public class CucumberHooks {
    private static final String SEPARATOR = "=".repeat(40);

    @BeforeAll
    public static void beforeAll() {
        LogUtils.info(SEPARATOR);
        LogUtils.info("STARTING TEST SUITE");
        LogUtils.info(SEPARATOR);
        PropertiesHelper.loadAllFiles();

        // ========== ENHANCEMENT: Initialize LoginDataHelper from Excel ==========
        try {
            String environment = ConstantGlobal.ENV != null ? ConstantGlobal.ENV : "dev";
            LoginDataHelper.initializeFromExcel(environment);
            LogUtils.info("✅ Login credentials loaded from Excel for environment: " + environment);
        } catch (Exception e) {
            LogUtils.warn("⚠️  Failed to load credentials from Excel: " + e.getMessage());
            LogUtils.warn("Falling back to ConstantGlobal configuration");
        }

        // ========== ENHANCEMENT: Log user info at suite level ==========
        LogUtils.info(UserInfoHelper.getUserTestHeader());
    }

    @AfterAll
    public static void afterAll() {
        LogUtils.info(SEPARATOR);
        LogUtils.info("TEST SUITE COMPLETED");
        LogUtils.info(SEPARATOR);
    }

    @Before
    public void beforeScenario(Scenario scenario) {
        LogUtils.info("SCENARIO START: " + scenario.getName());
        LogUtils.info("SCENARIO STATUS: Starting");

        if (DriverManager.getDriver() == null) {
            new DriverFactory().createDriver();
            LogUtils.info("Driver initialized for scenario: " + scenario.getName());
        }

        try {
            String testName = scenario.getName();
            ExtentTestManager.createTest(testName);
            LogUtils.info("ExtentTest initialized for: " + testName);

            // Log scenario info to ExtentReport
            if (ExtentTestManager.getTest() != null) {
                ExtentTestManager.getTest().info("Starting scenario: " + testName);

                // ========== ENHANCEMENT: Log user info from LoginDataHelper (Excel data) ==========
                String userEmail = LoginDataHelper.getCurrentEmail() != null ? 
                    LoginDataHelper.getCurrentEmail() : ConstantGlobal.VALID_EMAIL;
                String environment = LoginDataHelper.getCurrentEnvironment() != null ? 
                    LoginDataHelper.getCurrentEnvironment() : ConstantGlobal.ENV;
                String accountType = UserInfoHelper.getUserAccountType();

                ExtentTestManager.getTest().info("Test User: " + userEmail);
                ExtentTestManager.getTest().info("Environment: " + environment);
                ExtentTestManager.getTest().info("Account Type: " + accountType);
            }

            // ========== ENHANCEMENT: Attach user info to Allure Report ==========
            AllureManager.attachEnvironmentInfo();
            AllureManager.attachUserAccountInfo();

        } catch (Exception e) {
            LogUtils.info("Failed to create ExtentTest: " + e.getMessage());
        }
    }

    @After
    public void afterScenario(Scenario scenario) {
        String status = "PASSED";
        try {
            Object statusObj = scenario.getClass().getMethod("getStatus").invoke(scenario);
            if (statusObj != null) {
                status = statusObj.toString();
            } else {
                status = scenario.isFailed() ? "FAILED" : "PASSED";
            }
        } catch (NoSuchMethodException nsme) {
            status = scenario.isFailed() ? "FAILED" : "PASSED";
        } catch (Exception e) {
            status = scenario.isFailed() ? "FAILED" : "PASSED";
        }

        try {
            if (ExtentTestManager.getTest() != null) {
                if ("FAILED".equalsIgnoreCase(status)) {
                    ExtentTestManager.getTest().fail("Scenario Failed: " + scenario.getName());
                    // ========== ENHANCEMENT: Attach summary on failure ==========
                    AllureManager.attachTestResultSummary(scenario.getName(), "FAILED");
                } else if ("SKIPPED".equalsIgnoreCase(status) || "UNKNOWN".equalsIgnoreCase(status)) {
                    ExtentTestManager.getTest().skip("Scenario Skipped: " + scenario.getName());
                } else {
                    ExtentTestManager.getTest().pass("Scenario Passed: " + scenario.getName());
                    // ========== ENHANCEMENT: Attach summary on pass ==========
                    AllureManager.attachTestResultSummary(scenario.getName(), "PASSED");
                }
            }
        } catch (Exception e) {
            LogUtils.error("Failed to log scenario status to ExtentReport: " + e.getMessage());
        }

        LogUtils.info("SCENARIO FINISHED: " + scenario.getName());
        LogUtils.info("SCENARIO STATUS: " + status);

        DriverManager.quit();
        LogUtils.info(SEPARATOR + "\n");

        TestContext.reset();
    }

}

package steps;

import constants.ConstantGlobal;
import helpers.UserInfoHelper;
import hooks.TestContext;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import keywords.WebUI;
import pages.LoginPage;
import pages.models.CredentialsDataObject;
import reports.AllureManager;
import utils.LogUtils;

public class StepsLoginWithRegisteredCredentials {
    private TestContext testContext;
    private LoginPage loginPage;

    private final String validEmail = ConstantGlobal.VALID_EMAIL;
    private final String validPassword = ConstantGlobal.VALID_PASSWORD;

    public StepsLoginWithRegisteredCredentials(TestContext testContext) {
        this.testContext = testContext;
        this.loginPage = new LoginPage();
    }

    public StepsLoginWithRegisteredCredentials(){
        this(new TestContext());
    }

    @When("I enter registered email address and password")
    public void iEnterCorrectEmailAddressAndPassword() {
        // ========== ENHANCEMENT: Log user account info ==========
        LogUtils.info("Logging in with account: " + UserInfoHelper.getCurrentUserEmail());
        LogUtils.info("Account Type: " + UserInfoHelper.getUserAccountType());

        CredentialsDataObject credentialsData = CredentialsDataObject.builder()
                .userEmail(validEmail)
                .userPassword(validPassword)
                .build();

        loginPage.loginAccount(credentialsData);

        // ========== ENHANCEMENT: Attach user action to Allure ==========
        AllureManager.attachUserAccountInfo();
    }

    @Then("I verify that {string} is visible")
    public void iVerifyThatIsVisible(String expectedText) {
        String actualText = loginPage.getSuccessLogin();

        if ("Logged in as user email".equalsIgnoreCase(expectedText.trim())) {
            WebUI.verifyEquals(actualText, validEmail,
                    "Success login label is not showing the expected user email.");
            return;
        }

        WebUI.verifyEquals(actualText, expectedText,
                "Success login label is different from expected text.");
    }
}

package steps;

import constants.ConstantGlobal;
import helpers.LoginDataHelper;
import helpers.UserInfoHelper;
import hooks.TestContext;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import keywords.WebUI;
import pages.LoginPage;
import pages.models.CredentialsDataObject;
import reports.AllureManager;
import utils.LogUtils;

public class StepsLoginWithRegisteredCredentials {
    private TestContext testContext;
    private LoginPage loginPage;

    public StepsLoginWithRegisteredCredentials(TestContext testContext) {
        this.testContext = testContext;
        this.loginPage = new LoginPage();
    }

    public StepsLoginWithRegisteredCredentials(){
        this(new TestContext());
    }

    @When("I enter registered email address and password")
    public void iEnterCorrectEmailAddressAndPassword() {
        // ========== ENHANCEMENT: Get credentials from LoginDataHelper (Excel data) ==========
        String userEmail = LoginDataHelper.getCurrentEmail();
        String userPassword = LoginDataHelper.getCurrentPassword();

        LogUtils.info("Logging in with account: " + userEmail);
        LogUtils.info("Account Type: " + UserInfoHelper.getUserAccountType());
        LogUtils.info("Environment: " + LoginDataHelper.getCurrentEnvironment());

        CredentialsDataObject credentialsData = CredentialsDataObject.builder()
                .userEmail(userEmail)
                .userPassword(userPassword)
                .build();

        loginPage.loginAccount(credentialsData);

        // ========== ENHANCEMENT: Attach user action to Allure ==========
        AllureManager.attachUserAccountInfo();
    }

    @Then("I verify that {string} is visible")
    public void iVerifyThatIsVisible(String expectedText) {
        // ========== ENHANCEMENT: Get email from LoginDataHelper ==========
        String userEmail = LoginDataHelper.getCurrentEmail();
        String actualText = loginPage.getSuccessLogin();

        if ("Logged in as user email".equalsIgnoreCase(expectedText.trim())) {
            WebUI.verifyEquals(actualText, userEmail,
                    "Success login label is not showing the expected user email.");
            return;
        }

        WebUI.verifyEquals(actualText, expectedText,
                "Success login label is different from expected text.");
    }
}
